"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([["266"],{6164(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/docs/about","label":"About","docId":"about","unlisted":false},{"type":"link","href":"/docs/quick-start","label":"Quick Start","docId":"quick-start","unlisted":false},{"type":"link","href":"/docs/http","label":"HTTP","docId":"http","unlisted":false},{"type":"link","href":"/docs/js_runtime","label":"JavaScript Runtime","docId":"js_runtime","unlisted":false},{"type":"category","label":"Tools","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/tools/read_file","label":"read_file","docId":"tools/read_file","unlisted":false},{"type":"link","href":"/docs/tools/write_file","label":"write_file","docId":"tools/write_file","unlisted":false},{"type":"link","href":"/docs/tools/edit_file","label":"edit_file","docId":"tools/edit_file","unlisted":false},{"type":"link","href":"/docs/tools/move","label":"move","docId":"tools/move","unlisted":false},{"type":"link","href":"/docs/tools/glob","label":"glob","docId":"tools/glob","unlisted":false},{"type":"link","href":"/docs/tools/grep","label":"grep","docId":"tools/grep","unlisted":false},{"type":"link","href":"/docs/tools/fetch","label":"fetch","docId":"tools/fetch","unlisted":false},{"type":"link","href":"/docs/tools/js_repl","label":"js_repl","docId":"tools/js_repl","unlisted":false},{"type":"link","href":"/docs/tools/js_exec","label":"js_exec","docId":"tools/js_exec","unlisted":false}],"href":"/docs/category/tools"},{"type":"link","href":"/docs/runtime_docs","label":"Runtime Documentation","docId":"runtime_docs","unlisted":false}]},"docs":{"about":{"id":"about","title":"About","description":"SpadeBox provides a set of tools for AI agents with bindings in multiple languages and built-in lightweight sandboxing.","sidebar":"tutorialSidebar"},"http":{"id":"http","title":"HTTP","description":"SpadeBox can expose a fetch tool for agents to interact with HTTP services.","sidebar":"tutorialSidebar"},"js_runtime":{"id":"js_runtime","title":"JavaScript Runtime","description":"SpadeBox provides a sandboxed JavaScript runtime to enable safe code execution without requiring a bash tool.","sidebar":"tutorialSidebar"},"quick-start":{"id":"quick-start","title":"Quick Start","description":"SpadeBox provides a set of sandboxed tools for AI agents: file system access, HTTP fetching, and a JavaScript REPL. This page shows how to get up and running in TypeScript, Python, and Rust.","sidebar":"tutorialSidebar"},"runtime_docs":{"id":"runtime_docs","title":"Runtime Documentation","description":"Scope: global","sidebar":"tutorialSidebar"},"tools/edit_file":{"id":"tools/edit_file","title":"edit_file","description":"Replace text within a file. Reads the file, finds the exact string provided in \'oldstring\', and replaces it with \'newstring\'. By default the string must appear exactly once \u2014 include enough surrounding context in \'oldstring\' to make it unique. If the string appears multiple times and you want to replace all of them, set replaceall to true. Always read the file before editing to ensure \'old_string\' matches the current content exactly.","sidebar":"tutorialSidebar"},"tools/fetch":{"id":"tools/fetch","title":"fetch","description":"Perform an HTTP request and return the response body as text. The URL must use the http or https scheme. Available methods and domains are determined by the sandbox configuration.","sidebar":"tutorialSidebar"},"tools/glob":{"id":"tools/glob","title":"glob","description":"List files matching a glob pattern. Returns a newline-separated list of relative file paths sorted alphabetically. Use ` to match across directories (e.g. /.rs finds all Rust files, src//.ts` finds TypeScript files under src/). Use \'max_results\' to control the result cap (default 300; 0 = unlimited).","sidebar":"tutorialSidebar"},"tools/grep":{"id":"tools/grep","title":"grep","description":"Search file contents for a regex pattern (ripgrep). Returns matching lines with their file path and line number. Use \'glob\' to restrict the search to specific file types (e.g. \'/*.rs\'). Use \'contextlines\' to include N surrounding lines around each match. Use \'maxmatches\' to control the result cap (default 100; 0 = unlimited).","sidebar":"tutorialSidebar"},"tools/js_exec":{"id":"tools/js_exec","title":"js_exec","description":"Execute a JavaScript file in a fresh runtime and return an empty string on success, or an error message if the script throws. No state is shared with the JS REPL \u2014 each call starts from a clean context.","sidebar":"tutorialSidebar"},"tools/js_repl":{"id":"tools/js_repl","title":"js_repl","description":"Evaluate JavaScript code and return the result as a string. The session is persistent: variables and functions defined in one call are available in subsequent calls.","sidebar":"tutorialSidebar"},"tools/move":{"id":"tools/move","title":"move","description":"Move or rename a file or directory, or delete it. Provide \'src\' (source) and \'dst\' (destination) to move or rename. If \'dst\' already exists and \'overwrite\' is false (default), the call fails \u2014 set \'overwrite\' to true to replace it. Set \'create_dirs\' to true to create any missing intermediate directories for the destination. To delete instead of moving, omit \'dst\' and set \'delete\' to true.","sidebar":"tutorialSidebar"},"tools/read_file":{"id":"tools/read_file","title":"read_file","description":"Read the text content of a file. Provide a relative path (e.g. \'src/main.rs\' or \'README.md\'). Returns the file\'s content as a UTF-8 string. Use offset (1-indexed) and limit to read a specific range of lines.","sidebar":"tutorialSidebar"},"tools/write_file":{"id":"tools/write_file","title":"write_file","description":"Write text content to a file. Provide a relative path (e.g. \'src/main.rs\') and the full UTF-8 content to write. Creates the file if it does not exist, or overwrites it entirely if it does. If the file already exists, it must be read first \u2014 attempting to overwrite without a prior read will return an error. Set \'createdirs\' to true to create any missing intermediate directories automatically. To create a directory without writing a file, end the path with \'/\' (e.g. \'src/utils/\') and set \'createdirs\' to true \u2014 content is ignored in that case.","sidebar":"tutorialSidebar"}}}}')}}]);